import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from "recharts";
import api from "../utils/api";

function Section({ title, children }) {
  return (
    <div className="card" style={{ marginBottom: 20 }}>
      <h3 style={{ fontSize: 13, fontFamily: "var(--mono)", letterSpacing: "0.05em", color: "var(--text2)", textTransform: "uppercase", marginBottom: 18, borderBottom: "1px solid var(--border)", paddingBottom: 12 }}>
        {title}
      </h3>
      {children}
    </div>
  );
}

function InfoGrid({ data }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: 14 }}>
      {data.map(([label, value, warn]) => (
        <div key={label} style={{ background: "var(--bg3)", borderRadius: 4, padding: "10px 14px" }}>
          <div style={{ fontSize: 10, fontFamily: "var(--mono)", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 4 }}>
            {label}
          </div>
          <div style={{ fontFamily: "var(--mono)", fontSize: 15, fontWeight: 700, color: warn ? "var(--warn)" : "var(--text)" }}>
            {value ?? "—"}
          </div>
        </div>
      ))}
    </div>
  );
}

const INTERVENTION_ICONS = {
  counselling: "🧠",
  extra_classes: "📚",
  study_plan: "📋",
  attendance_monitoring: "📊",
  academic_support: "🎯",
  wellness_check: "❤️",
  motivation_session: "🚀",
  progress_monitoring: "📈",
};

export default function StudentDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [student, setStudent] = useState(null);
  const [interventions, setInterventions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [predicting, setPredicting] = useState(false);
  const [generating, setGenerating] = useState(false);

  const load = async () => {
    const [sRes, iRes] = await Promise.all([
      api.get(`/students/${id}`),
      api.get(`/predictions/interventions/student/${id}`),
    ]);
    setStudent(sRes.data);
    setInterventions(iRes.data);
  };

  useEffect(() => {
    load().catch(() => {}).finally(() => setLoading(false));
  }, [id]);

  const runPredict = async () => {
    setPredicting(true);
    try {
      await api.post(`/predictions/predict/${id}`);
      await load();
    } catch {}
    setPredicting(false);
  };

  const generateInterventions = async () => {
    setGenerating(true);
    try {
      const res = await api.post(`/predictions/interventions/generate/${id}`);
      setInterventions(res.data);
    } catch (e) {
      alert(e.response?.data?.detail || "Failed to generate interventions");
    }
    setGenerating(false);
  };

  const updateIntervention = async (iid, status) => {
    await api.patch(`/predictions/interventions/${iid}`, { status });
    setInterventions(iv => iv.map(i => i.id === iid ? { ...i, status } : i));
  };

  if (loading) return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "60vh" }}>
      <div style={{ fontFamily: "var(--mono)", color: "var(--text2)", animation: "pulse 1.5s infinite" }}>
        Loading student data...
      </div>
    </div>
  );

  if (!student) return (
    <div className="card" style={{ textAlign: "center", padding: 60 }}>
      <div style={{ color: "var(--text2)" }}>Student not found.</div>
      <button className="btn btn-secondary" style={{ marginTop: 16 }} onClick={() => navigate("/students")}>
        ← Back
      </button>
    </div>
  );

  const pred = student.latest_prediction;
  const riskScore = pred ? Math.round(pred.risk_score * 100) : null;
  const riskColor = pred?.risk_label === "high" ? "var(--danger)" : pred?.risk_label === "medium" ? "var(--warn)" : pred?.risk_label === "low" ? "var(--safe)" : "var(--text2)";

  // SHAP chart data
  const shapData = pred?.top_factors?.map(f => ({
    name: f.feature,
    value: Math.abs(f.shap_value),
    raw: f.shap_value,
    impact: f.impact,
    description: f.description,
  })) || [];

  return (
    <div className="fade-in">
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28 }}>
        <div>
          <button className="btn btn-ghost btn-sm" style={{ marginBottom: 12 }} onClick={() => navigate("/students")}>
            ← Back
          </button>
          <h1 style={{ fontSize: 26, letterSpacing: 1 }}>{student.name}</h1>
          <div style={{ display: "flex", gap: 12, alignItems: "center", marginTop: 6 }}>
            <span style={{ fontFamily: "var(--mono)", fontSize: 12, color: "var(--text3)" }}>{student.student_id}</span>
            {pred && <span className={`badge badge-${pred.risk_label}`}>● {pred.risk_label} risk</span>}
          </div>
        </div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "flex-end" }}>
          <button className="btn btn-secondary" disabled={predicting} onClick={runPredict}>
            {predicting ? "Predicting..." : "⟳ Re-Predict"}
          </button>
          <button className="btn btn-primary" disabled={generating || !pred} onClick={generateInterventions}>
            {generating ? "Generating..." : "✦ Generate Interventions"}
          </button>
        </div>
      </div>

      {/* Risk Score Banner */}
      {pred && (
        <div className="card" style={{
          marginBottom: 20, padding: "20px 28px",
          background: `linear-gradient(135deg, var(--bg2) 0%, rgba(${pred.risk_label === "high" ? "255,60,95" : pred.risk_label === "medium" ? "255,184,48" : "0,214,143"},0.08) 100%)`,
          borderLeft: `4px solid ${riskColor}`,
          display: "flex", gap: 32, alignItems: "center", flexWrap: "wrap",
        }}>
          <div>
            <div style={{ fontSize: 11, fontFamily: "var(--mono)", color: "var(--text2)", textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 4 }}>
              Failure Risk Score
            </div>
            <div style={{ fontSize: 52, fontFamily: "var(--mono)", fontWeight: 700, color: riskColor, lineHeight: 1 }}>
              {riskScore}%
            </div>
          </div>
          <div style={{ flex: 1, minWidth: 200 }}>
            <div style={{ height: 8, background: "var(--bg3)", borderRadius: 4, overflow: "hidden", marginBottom: 10 }}>
              <div style={{ width: `${riskScore}%`, height: "100%", background: riskColor, borderRadius: 4, transition: "width 1s ease" }} />
            </div>
            <div style={{ fontSize: 13, color: "var(--text2)" }}>
              {pred.risk_label === "high"
                ? "⚠ Immediate intervention required. This student is at high risk of failure."
                : pred.risk_label === "medium"
                ? "◈ Moderate risk detected. Monitor closely and apply support measures."
                : "✓ Student is performing within acceptable range. Continue monitoring."}
            </div>
            <div style={{ fontSize: 11, fontFamily: "var(--mono)", color: "var(--text3)", marginTop: 6 }}>
              Model: {pred.model_version} · {new Date(pred.created_at).toLocaleDateString()}
            </div>
          </div>
        </div>
      )}

      {!pred && (
        <div className="card" style={{ marginBottom: 20, textAlign: "center", padding: 32, border: "1px dashed var(--border2)" }}>
          <div style={{ color: "var(--text2)", marginBottom: 12 }}>No prediction yet for this student.</div>
          <button className="btn btn-primary" onClick={runPredict} disabled={predicting}>
            {predicting ? "Running..." : "⟳ Run Prediction Now"}
          </button>
        </div>
      )}

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
        {/* Left column */}
        <div>
          {/* Academic Info */}
          <Section title="Academic Profile">
            <InfoGrid data={[
              ["Age", student.age],
              ["Gender", student.gender],
              ["School", student.school],
              ["Study Time (h/w)", student.studytime],
              ["Failures", student.failures, student.failures > 0],
              ["Absences", student.absences, student.absences > 15],
              ["G1 (Period 1)", student.g1, student.g1 < 8],
              ["G2 (Period 2)", student.g2, student.g2 < 8],
              ["G3 (Final)", student.g3, student.g3 < 10],
              ["Higher Edu.", student.higher],
              ["School Support", student.schoolsup],
              ["Paid Classes", student.paid],
            ]} />
          </Section>

          {/* Family Info */}
          <Section title="Family & Background">
            <InfoGrid data={[
              ["Family Size", student.famsize],
              ["Parents Status", student.pstatus],
              ["Mother's Edu.", student.medu],
              ["Father's Edu.", student.fedu],
              ["Mother's Job", student.mjob],
              ["Father's Job", student.fjob],
              ["Guardian", student.guardian],
              ["Family Rel.", student.famrel],
              ["Internet", student.internet],
              ["Travel Time", student.traveltime],
            ]} />
          </Section>
        </div>

        {/* Right column */}
        <div>
          {/* SHAP Explainability */}
          {shapData.length > 0 && (
            <Section title="⚡ XAI — Why This Prediction?">
              <p style={{ fontSize: 12, color: "var(--text2)", marginBottom: 16, lineHeight: 1.7 }}>
                SHAP (SHapley Additive exPlanations) values show which factors most influenced this prediction. Red = increases risk, green = decreases risk.
              </p>
              <ResponsiveContainer width="100%" height={200}>
                <BarChart data={shapData} layout="vertical" margin={{ left: 20, right: 20 }}>
                  <CartesianGrid stroke="var(--border)" strokeDasharray="3 3" horizontal={false} />
                  <XAxis type="number" stroke="var(--text3)" tick={{ fontSize: 10, fontFamily: "var(--mono)" }} />
                  <YAxis type="category" dataKey="name" stroke="var(--text3)" tick={{ fontSize: 11, fontFamily: "var(--mono)" }} width={80} />
                  <Tooltip
                    formatter={(v, n, props) => [props.payload.raw.toFixed(4), "SHAP Value"]}
                    contentStyle={{ background: "var(--bg3)", border: "1px solid var(--border)", borderRadius: 4, fontSize: 12 }}
                  />
                  <Bar dataKey="value" radius={2}>
                    {shapData.map((entry, i) => (
                      <Cell key={i} fill={entry.impact === "increases_risk" ? "var(--danger)" : "var(--safe)"} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>

              {/* Factor list */}
              <div style={{ marginTop: 16, display: "flex", flexDirection: "column", gap: 10 }}>
                {pred?.top_factors?.map((f, i) => (
                  <div key={i} style={{
                    display: "flex", gap: 12, alignItems: "flex-start",
                    background: "var(--bg3)", borderRadius: 4, padding: "10px 14px",
                    borderLeft: `3px solid ${f.impact === "increases_risk" ? "var(--danger)" : "var(--safe)"}`,
                  }}>
                    <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: f.impact === "increases_risk" ? "var(--danger)" : "var(--safe)", minWidth: 40, fontWeight: 700 }}>
                      {f.impact === "increases_risk" ? "▲" : "▼"} {Math.abs(f.shap_value).toFixed(3)}
                    </div>
                    <div>
                      <div style={{ fontFamily: "var(--mono)", fontSize: 11, fontWeight: 700, marginBottom: 2 }}>{f.feature.toUpperCase()}</div>
                      <div style={{ fontSize: 12, color: "var(--text2)" }}>{f.description}</div>
                    </div>
                  </div>
                ))}
              </div>
            </Section>
          )}

          {/* Lifestyle */}
          <Section title="Lifestyle Factors">
            <InfoGrid data={[
              ["Freetime", student.freetime],
              ["Goes Out", student.goout, student.goout >= 4],
              ["Weekday Alcohol", student.dalc, student.dalc >= 3],
              ["Weekend Alcohol", student.walc, student.walc >= 3],
              ["Health Status", student.health],
              ["Romantic", student.romantic],
              ["Activities", student.activities],
            ]} />
          </Section>
        </div>
      </div>

      {/* Interventions */}
      <Section title={`✦ Intervention Plans (${interventions.length})`}>
        {interventions.length === 0 ? (
          <div style={{ textAlign: "center", padding: "24px 0", color: "var(--text2)" }}>
            <div style={{ marginBottom: 12 }}>No interventions yet.</div>
            <button className="btn btn-primary btn-sm" disabled={!pred || generating} onClick={generateInterventions}>
              {generating ? "Generating..." : "✦ Auto-Generate with AI"}
            </button>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {interventions.map(iv => (
              <div key={iv.id} style={{
                background: "var(--bg3)", borderRadius: 6, padding: "16px 20px",
                borderLeft: `3px solid ${iv.status === "completed" ? "var(--safe)" : iv.status === "in_progress" ? "var(--info)" : "var(--border2)"}`,
                display: "flex", gap: 16, alignItems: "flex-start",
              }}>
                <div style={{ fontSize: 24, flexShrink: 0 }}>
                  {INTERVENTION_ICONS[iv.intervention_type] || "📌"}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6, flexWrap: "wrap", gap: 8 }}>
                    <span style={{ fontFamily: "var(--mono)", fontSize: 11, textTransform: "uppercase", fontWeight: 700, color: "var(--text2)" }}>
                      {iv.intervention_type.replace(/_/g, " ")}
                    </span>
                    <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                      {iv.ai_generated && (
                        <span style={{ fontSize: 10, fontFamily: "var(--mono)", color: "var(--purple)", background: "rgba(155,93,229,0.1)", padding: "2px 8px", borderRadius: 100 }}>
                          AI
                        </span>
                      )}
                      <span style={{
                        fontSize: 10, fontFamily: "var(--mono)", textTransform: "uppercase",
                        color: iv.status === "completed" ? "var(--safe)" : iv.status === "in_progress" ? "var(--info)" : "var(--text3)",
                      }}>
                        {iv.status}
                      </span>
                    </div>
                  </div>
                  <p style={{ fontSize: 13, color: "var(--text2)", lineHeight: 1.6, marginBottom: 12 }}>{iv.description}</p>
                  <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    {iv.status === "pending" && (
                      <button className="btn btn-sm btn-secondary" onClick={() => updateIntervention(iv.id, "in_progress")}>
                        ▶ Start
                      </button>
                    )}
                    {iv.status === "in_progress" && (
                      <button className="btn btn-sm btn-success" onClick={() => updateIntervention(iv.id, "completed")}>
                        ✓ Complete
                      </button>
                    )}
                    {iv.status === "completed" && (
                      <span style={{ fontSize: 12, color: "var(--safe)" }}>✓ Completed</span>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </Section>
    </div>
  );
}
